WITH version AS (
  SELECT nv.id
  FROM norma_versiones nv
  JOIN normas n ON n.id = nv.norma_id
  WHERE n.codigo = 'NTC-ISO-21101' AND nv.version = '2020'
),
req AS (
  SELECT r.id, r.codigo
  FROM requisitos_normativos r
  JOIN version v ON v.id = r.norma_version_id
